    [EntityBehaviourDefinition(VanillaContraptionNames.drivenser)]
    public class Drivenser : DispenserFamily
    {
        public Drivenser(string nsp, string name) : base(nsp, name)
        {
        }

        public override void Init(Entity entity)
        {
            base.Init(entity);
            InitShootTimer(entity);
            SetRepeatTimer(entity, new FrameTimer(15));
            if (entity.Level.IsIZombie())
            {
                SetUpgradeLevel(entity, I_ZOMBIE_LEVEL);
            }
        }
        protected override void UpdateAI(Entity entity)
        {
            base.UpdateAI(entity);
            if (!entity.IsEvoked())
            {
                ShootTick(entity);
                int repeatCount = GetRepeatCount(entity);
                if (repeatCount > 0)
                {
                    var repeatTimer = GetRepeatTimer(entity);
                    if (repeatTimer.RunToExpiredAndNotNull(entity.GetAttackSpeed()))
                    {
                        Shoot(entity);
                        SetRepeatCount(entity, repeatCount - 1);
                        repeatTimer.Reset();
                    }
                }
            }
            else
            {
                var shootTimer = GetShootTimer(entity);

                // 如果是触发大招，射速更快（间隔更短）  
                int shootInterval = GetIsTriggerEvoke(entity) ? GetTimerTime(entity)/2 : GetTimerTime(entity);

                if (shootTimer.RunToExpiredAndNotNull())
                {
                    entity.TriggerAnimation("Shoot");
                    var shootParams = entity.GetShootParams();
                    shootParams.projectileID = VanillaProjectileID.largeArrow;
                    shootParams.damage = entity.GetDamage() * 30;
                    shootParams.soundID = VanillaSoundID.spellCard;
                    shootParams.velocity = shootParams.velocity.normalized;
                    entity.ShootProjectile(shootParams);

                    int repeatCount = GetRepeatCount(entity);
                    repeatCount--;
                    SetRepeatCount(entity, repeatCount);
                    if (repeatCount <= 0)
                    {
                        entity.SetEvoked(false);

                        // 如果是触发大招，发射完毕后自毁  
                        if (GetIsTriggerEvoke(entity))
                        {
                            Explode(entity, 60, 600);
                            entity.TakeDamage(99999, new DamageEffectList(), entity);
                        }

                        SetIsTriggerEvoke(entity, false); // 重置标志  
                    }
                    shootTimer.ResetTime(shootInterval);
                }
            }
            var blockerBlend = GetBlockerBlend(entity);
            blockerBlend = blockerBlend * 0.5f + GetUpgradeLevel(entity) * 0.5f;
            SetBlockerBlend(entity, blockerBlend);
        }
        public static DamageOutput[] Explode(Entity entity, float range, float damage)
        {
            var damageEffects = new DamageEffectList(VanillaDamageEffects.MUTE, VanillaDamageEffects.DAMAGE_BODY_AFTER_ARMOR_BROKEN, VanillaDamageEffects.EXPLOSION);
            var damageOutputs = entity.Level.Explode(entity.Position, range, VanillaFactions.NEUTRAL, damage, damageEffects, entity);
            foreach (var output in damageOutputs)
            {
                var result = output.BodyResult;
                if (result != null && result.Fatal)
                {
                    var target = output.Entity;
                    var distance = (target.Position - entity.Position).magnitude;
                    var speed = 25 * Mathf.Lerp(1f, 0.5f, distance / range);
                    target.Velocity = target.Velocity + Vector3.up * speed;
                }
            }
            Explosion.Spawn(entity, entity.GetCenter(), range);
            entity.PlaySound(VanillaSoundID.explosion);
            entity.Level.ShakeScreen(10, 0, 15);


            return damageOutputs;
        }
        protected override void UpdateLogic(Entity entity)
        {
            base.UpdateLogic(entity);
            var blend = GetBlockerBlend(entity);
            entity.SetModelProperty("Level", GetUpgradeLevel(entity));
            entity.SetAnimationFloat("BlockerBlend", blend);
            entity.SetAnimationFloat("RotateSpeed", blend + 1);
        }
        public override void OnShootTick(Entity entity)
        {
            int baseLevel = GetUpgradeLevel(entity);
            int effectiveLevel = baseLevel;

            // 如果有触发buff，挡位可以提升到6，且每个挡位+2箭矢    
            if (entity.HasBuff<DrivenserTriggerBuff>())
            {
                effectiveLevel = Mathf.Min(baseLevel, TRIGGER_MAX_LEVEL);
                int count = effectiveLevel * 2 + 2 + TRIGGER_ARROW_BONUS; // 每个挡位+2箭矢    
                SetRepeatCount(entity, count);
            }
            else
            {
                int count = baseLevel * 2 + 2;
                SetRepeatCount(entity, count);
            }

            var repeatTimer = GetRepeatTimer(entity);
            if (repeatTimer != null)
            {
                int count = GetRepeatCount(entity);
                repeatTimer.ResetTime(Mathf.FloorToInt(15f / count));
                repeatTimer.Frame = 0;
            }
        }

        // 添加触发方法    
        public override bool CanTrigger(Entity entity)
        {
            return base.CanTrigger(entity) && !entity.HasBuff<DrivenserTriggerBuff>();
        }

        protected override void OnTrigger(Entity entity)
        {
            base.OnTrigger(entity);

            entity.TakeDamage(75, new DamageEffectList(), entity);

            // 添加触发buff，持续30秒    
            entity.AddBuff<DrivenserTriggerBuff>();

            // 播放音效和特效    
            entity.PlaySound(VanillaSoundID.mechanism);
            entity.Level.Spawn(VanillaEffectID.gearParticles, entity.Position, entity);
        }

